      "path": "src/modules/projects/service.js",
      "content": "const { randomUUID } = require('node:crypto');
const projects = {};
function createProject(data) {
  const id = randomUUID();
  projects[id] = { ...data, id };
  return projects[id];
}
function addMember(projectId, data) {
  if (!projects[projectId]) throw new Error('NOT_FOUND');
  projects[projectId].members = projects[projectId].members || [];
  projects[projectId].members.push({ id: randomUUID(), ...data });
  return projects[projectId].members[projects[projectId].members.length - 1];
}
exports.createProject = createProject;
exports.addMember = addMember;
